const getSeason = (ep) => parseInt(ep[2].match(/S(\d+)/)[1]);

const STORAGE_KEY = "arrowverse_watched_v2";

function loadWatched() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? new Set(JSON.parse(raw)) : new Set();
  } catch { return new Set(); }
}

function saveWatched(set) {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify([...set])); } catch {}
}

export default function App() {
  const [watched, setWatched] = useState(() => loadWatched());
  const [page, setPage] = useState("tracker");
  const [filterSeries, setFilterSeries] = useState("all");
  const [filterWatched, setFilterWatched] = useState("all");
  const [search, setSearch] = useState("");
  const [expandedSeries, setExpandedSeries] = useState(null);

  const toggleWatched = (id) => {
    setWatched(prev => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      saveWatched(next);
      return next;
    });
  };

  const filtered = useMemo(() => {
    return EPISODES.filter(ep => {
      if (filterSeries !== "all" && ep[1] !== filterSeries) return false;
      if (filterWatched === "watched" && !watched.has(ep[0])) return false;
      if (filterWatched === "unwatched" && watched.has(ep[0])) return false;
      if (search && !ep[3].toLowerCase().includes(search.toLowerCase()) && !ep[2].toLowerCase().includes(search.toLowerCase())) return false;
      return true;
    });
  }, [filterSeries, filterWatched, search, watched]);

  const totalWatched = watched.size;
  const totalEps = EPISODES.length;
  const pct = Math.round((totalWatched / totalEps) * 100);

  const statsData = useMemo(() => {
    return SERIES_LIST.map(series => {
      const eps = EPISODES.filter(e => e[1] === series);
      const watchedCount = eps.filter(e => watched.has(e[0])).length;
      const seasons = [...new Set(eps.map(e => getSeason(e)))].sort((a,b)=>a-b);
      const seasonData = seasons.map(s => {
        const sEps = eps.filter(e => getSeason(e) === s);
        const sWatched = sEps.filter(e => watched.has(e[0])).length;
        return { season: s, total: sEps.length, watched: sWatched, pct: Math.round((sWatched/sEps.length)*100) };
      });
      return { series, total: eps.length, watched: watchedCount, pct: Math.round((watchedCount/eps.length)*100), seasons: seasonData };
    });
  }, [watched]);

  return (
    <div style={{ minHeight: "100vh", background: "#0a0a0f", color: "#e8e8f0", fontFamily: "'Bebas Neue', 'Georgia', serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Inter:wght@300;400;500&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        ::-webkit-scrollbar { width: 4px; } ::-webkit-scrollbar-track { background: #0a0a0f; } ::-webkit-scrollbar-thumb { background: #333; border-radius: 2px; }
        .ep-row:hover { background: rgba(255,255,255,0.04) !important; }
        .ep-check:hover { opacity: 0.8; cursor: pointer; }
        .nav-btn { background: none; border: none; cursor: pointer; padding: 8px 20px; font-family: 'Bebas Neue', serif; font-size: 18px; letter-spacing: 2px; transition: all 0.2s; color: #666; }
        .nav-btn.active { color: #e8e8f0; border-bottom: 2px solid #c1121f; }
        .nav-btn:hover { color: #aaa; }
        @media (max-width: 600px) {
          .ep-row { grid-template-columns: 6px 1fr 28px !important; gap: 10px !important; padding: 10px 12px !important; }
          .ep-num { display: none !important; }
          .ep-code { display: none !important; }
          .ep-date { display: none !important; }
          .ep-info { display: flex; flex-direction: column; }
          .ep-series-label { display: block !important; }
        }
        .filter-btn { background: none; border: 1px solid #333; border-radius: 4px; cursor: pointer; padding: 5px 14px; font-family: 'Inter', sans-serif; font-size: 12px; color: #888; transition: all 0.2s; white-space: nowrap; }
        .filter-btn.active { background: #c1121f; border-color: #c1121f; color: #fff; }
        .filter-btn:hover:not(.active) { border-color: #555; color: #ccc; }
        .series-card { border: 1px solid #1a1a2e; border-radius: 8px; overflow: hidden; transition: border-color 0.2s; }
        .series-card:hover { border-color: #333; }
        .expand-btn { background: none; border: none; cursor: pointer; color: #666; font-size: 12px; padding: 4px 8px; transition: color 0.2s; }
        .expand-btn:hover { color: #aaa; }
      `}</style>

      {/* Header */}
      <div style={{ background: "#0d0d18", borderBottom: "1px solid #1a1a2e", padding: "0 24px" }}>
        <div style={{ maxWidth: 1100, margin: "0 auto" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "16px 0 0" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
              <div style={{ width: 8, height: 32, background: "#c1121f", borderRadius: 2 }} />
              <span style={{ fontFamily: "'Bebas Neue', serif", fontSize: 28, letterSpacing: 4, color: "#fff" }}>ARROWVERSE</span>
              <span style={{ fontFamily: "'Inter', sans-serif", fontSize: 11, color: "#c1121f", letterSpacing: 3, paddingTop: 6, fontWeight: 500 }}>TRACKER</span>
            </div>
            <div style={{ fontFamily: "'Inter', sans-serif", fontSize: 12, color: "#555", textAlign: "right" }}>
              <div style={{ color: "#c1121f", fontSize: 20, fontFamily: "'Bebas Neue', serif", letterSpacing: 2 }}>{totalWatched}/{totalEps}</div>
              <div>episodi visti · {pct}%</div>
            </div>
          </div>
          <div style={{ display: "flex", gap: 4, marginTop: 8 }}>
            {["tracker","statistiche"].map(p => (
              <button key={p} className={`nav-btn${page===p?" active":""}`} onClick={() => setPage(p)}>
                {p.charAt(0).toUpperCase() + p.slice(1)}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 1100, margin: "0 auto", padding: "24px" }}>

        {page === "tracker" && (
          <>
            {/* Progress bar */}
            <div style={{ marginBottom: 24, background: "#111", borderRadius: 4, height: 4, overflow: "hidden" }}>
              <div style={{ height: "100%", background: "linear-gradient(90deg, #c1121f, #e63946)", width: `${pct}%`, transition: "width 0.5s ease", borderRadius: 4 }} />
            </div>

            {/* Filters */}
            <div style={{ display: "flex", gap: 8, marginBottom: 20, flexWrap: "wrap", alignItems: "center" }}>
              <input
                value={search}
                onChange={e => setSearch(e.target.value)}
                placeholder="Cerca episodio..."
                style={{ background: "#111", border: "1px solid #222", borderRadius: 4, padding: "6px 12px", color: "#e8e8f0", fontFamily: "'Inter', sans-serif", fontSize: 13, width: 200, outline: "none" }}
              />
              <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
                {["all","watched","unwatched"].map(f => (
                  <button key={f} className={`filter-btn${filterWatched===f?" active":""}`} onClick={() => setFilterWatched(f)}>
                    {f === "all" ? "Tutti" : f === "watched" ? "Visti" : "Da vedere"}
                  </button>
                ))}
              </div>
              <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
                <button className={`filter-btn${filterSeries==="all"?" active":""}`} onClick={() => setFilterSeries("all")}>Tutte le serie</button>
                {SERIES_LIST.map(s => (
                  <button key={s} className={`filter-btn${filterSeries===s?" active":""}`} onClick={() => setFilterSeries(s)}
                    style={filterSeries===s ? {} : {}}>
                    {SERIES_SHORT[s] || s.slice(0,3)}
                  </button>
                ))}
              </div>
            </div>

            {/* Count */}
            <div style={{ fontFamily: "'Inter', sans-serif", fontSize: 12, color: "#555", marginBottom: 12 }}>
              {filtered.length} episodi
            </div>

            {/* Episode list */}
            <div style={{ background: "#0d0d18", borderRadius: 8, border: "1px solid #1a1a2e", overflow: "hidden" }}>
              {filtered.length === 0 && (
                <div style={{ padding: 40, textAlign: "center", fontFamily: "'Inter', sans-serif", color: "#555", fontSize: 14 }}>Nessun episodio trovato</div>
              )}
              {filtered.map((ep, i) => {
                const isWatched = watched.has(ep[0]);
                const color = SERIES_COLORS[ep[1]] || "#555";
                return (
                  <div
                    key={ep[0]}
                    className="ep-row"
                    onClick={() => toggleWatched(ep[0])}
                    style={{
                      display: "grid", gridTemplateColumns: "48px 6px 90px 1fr 90px 32px",
                      alignItems: "center", gap: 12, padding: "10px 16px",
                      borderBottom: i < filtered.length - 1 ? "1px solid #111" : "none",
                      cursor: "pointer",
                      background: isWatched ? "rgba(193,18,31,0.04)" : "transparent",
                      transition: "background 0.15s",
                    }}
                  >
                    <span className="ep-num" style={{ fontFamily: "'Inter', sans-serif", fontSize: 11, color: "#444", textAlign: "right" }}>#{ep[0]}</span>
                    <div style={{ width: 3, height: 28, background: color, borderRadius: 2, opacity: isWatched ? 0.4 : 1 }} />
                    <span className="ep-code" style={{ fontFamily: "'Inter', sans-serif", fontSize: 11, color: isWatched ? "#555" : "#888", letterSpacing: 1 }}>{ep[2]}</span>
                    <div className="ep-info">
                      <div style={{ fontFamily: "'Inter', sans-serif", fontSize: 13, color: isWatched ? "#555" : "#ddd", textDecoration: isWatched ? "line-through" : "none", textDecorationColor: "#444" }}>{ep[3]}</div>
                      <div style={{ fontFamily: "'Inter', sans-serif", fontSize: 11, color: "#555", marginTop: 2 }}>{ep[1]} · <span style={{ color: "#444" }}>{ep[2]}</span></div>
                    </div>
                    <span className="ep-date" style={{ fontFamily: "'Inter', sans-serif", fontSize: 11, color: "#444" }}>{ep[4].split("-").reverse().join("/").slice(0,-5)}</span>
                    <div style={{
                      width: 24, height: 24, borderRadius: "50%",
                      border: `2px solid ${isWatched ? "#c1121f" : "#333"}`,
                      background: isWatched ? "#c1121f" : "transparent",
                      display: "flex", alignItems: "center", justifyContent: "center",
                      transition: "all 0.2s", flexShrink: 0
                    }}>
                      {isWatched && <span style={{ color: "#fff", fontSize: 11, lineHeight: 1 }}>✓</span>}
                    </div>
                  </div>
                );
              })}
            </div>
          </>
        )}

        {page === "statistiche" && (
          <>
            {/* Global stats */}
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))", gap: 12, marginBottom: 32 }}>
              {[
                { label: "Episodi totali", value: totalEps },
                { label: "Visti", value: totalWatched },
                { label: "Da vedere", value: totalEps - totalWatched },
                { label: "Completamento", value: `${pct}%` },
              ].map(s => (
                <div key={s.label} style={{ background: "#0d0d18", border: "1px solid #1a1a2e", borderRadius: 8, padding: "16px 20px" }}>
                  <div style={{ fontFamily: "'Inter', sans-serif", fontSize: 11, color: "#555", marginBottom: 6, letterSpacing: 1 }}>{s.label.toUpperCase()}</div>
                  <div style={{ fontFamily: "'Bebas Neue', serif", fontSize: 32, letterSpacing: 2, color: "#e8e8f0" }}>{s.value}</div>
                </div>
              ))}
            </div>

            {/* Per series */}
            <div style={{ fontFamily: "'Bebas Neue', serif", fontSize: 20, letterSpacing: 3, color: "#666", marginBottom: 16 }}>PER SERIE</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
              {statsData.map(s => (
                <div key={s.series} className="series-card" style={{ background: "#0d0d18" }}>
                  <div
                    style={{ padding: "14px 18px", cursor: "pointer", display: "flex", alignItems: "center", gap: 12 }}
                    onClick={() => setExpandedSeries(expandedSeries === s.series ? null : s.series)}
                  >
                    <div style={{ width: 4, height: 32, background: SERIES_COLORS[s.series] || "#555", borderRadius: 2, flexShrink: 0 }} />
                    <div style={{ flex: 1 }}>
                      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 6 }}>
                        <span style={{ fontFamily: "'Bebas Neue', serif", fontSize: 17, letterSpacing: 2, color: "#ddd" }}>{s.series}</span>
                        <span style={{ fontFamily: "'Inter', sans-serif", fontSize: 12, color: "#666" }}>{s.watched}/{s.total} · <span style={{ color: s.pct === 100 ? "#2d6a4f" : "#c1121f" }}>{s.pct}%</span></span>
                      </div>
                      <div style={{ background: "#111", borderRadius: 2, height: 3, overflow: "hidden" }}>
                        <div style={{ height: "100%", background: SERIES_COLORS[s.series] || "#c1121f", width: `${s.pct}%`, borderRadius: 2, transition: "width 0.4s" }} />
                      </div>
                    </div>
                    <button className="expand-btn">{expandedSeries === s.series ? "▲" : "▼"}</button>
                  </div>

                  {expandedSeries === s.series && (
                    <div style={{ padding: "0 18px 16px", borderTop: "1px solid #111" }}>
                      <div style={{ paddingTop: 14, display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(120px, 1fr))", gap: 8 }}>
                        {s.seasons.map(sea => (
                          <div key={sea.season} style={{ background: "#111", borderRadius: 6, padding: "10px 12px" }}>
                            <div style={{ fontFamily: "'Bebas Neue', serif", fontSize: 14, letterSpacing: 2, color: "#888", marginBottom: 6 }}>
                              STAGIONE {sea.season}
                            </div>
                            <div style={{ fontFamily: "'Inter', sans-serif", fontSize: 12, color: "#666", marginBottom: 6 }}>{sea.watched}/{sea.total} ep.</div>
                            <div style={{ background: "#1a1a1a", borderRadius: 2, height: 3, overflow: "hidden" }}>
                              <div style={{ height: "100%", background: SERIES_COLORS[s.series], width: `${sea.pct}%`, borderRadius: 2, transition: "width 0.4s" }} />
                            </div>
                            <div style={{ fontFamily: "'Bebas Neue', serif", fontSize: 16, color: sea.pct === 100 ? "#2d6a4f" : "#aaa", marginTop: 4 }}>{sea.pct}%</div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </>
        )}
      </div>
    </div>
  );
}
